        todaysAppointments = await DbContext.Appointments
            .Include(a => a.Patient)
            .Where(a => a.DateTime.Date == today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.DateTime)
            .ToListAsync();

        recentPatients = await DbContext.Patients
            .Include(p => p.Owner)
