@code {
    private bool loading = true;
    private List<Appointment> todaysAppointments = new();
    private List<Patient> recentPatients = new();
    private int unpaidCount;
    private decimal unpaidTotal;

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        todaysAppointments = await DbContext.Appointments
            .Include(a => a.Patient)
            .Where(a => a.DateTime.Date == today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.DateTime)
            .ToListAsync();

        recentPatients = await DbContext.Patients
            .Include(p => p.Owner)
            .OrderByDescending(p => p.Id)
            .Take(5)
            .ToListAsync();

        var unpaidInvoices = await DbContext.Invoices
            .Where(i => !i.IsPaid)
            .ToListAsync();
        unpaidCount = unpaidInvoices.Count;
        unpaidTotal = unpaidInvoices.Sum(i => i.TotalAmount);

        loading = false;
    }
}
