@page "/"
@attribute [Authorize]
@inject ApplicationDbContext DbContext

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1 class="mb-4">Dashboard</h1>

@if (loading)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="row">
        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Today's Appointments</h5>
                    <h2 class="text-primary">@todaysAppointments.Count</h2>
                    @foreach (var apt in todaysAppointments.Take(5))
                    {
                        <div class="small">
                            @apt.DateTime.ToString("HH:mm") - @apt.Patient.Name (@apt.Reason)
                        </div>
                    }
                    <a href="appointments" class="btn btn-sm btn-outline-primary mt-2">View All</a>
                </div>
            </div>
        </div>

        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Recent Patients</h5>
                    <h2 class="text-success">@recentPatients.Count</h2>
                    @foreach (var p in recentPatients)
                    {
                        <div class="small">@p.Name (@p.Species) - Owner: @p.Owner.LastName</div>
                    }
                    <a href="patients" class="btn btn-sm btn-outline-success mt-2">View All</a>
                </div>
            </div>
        </div>

        <div class="col-md-4 mb-3">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Unpaid Invoices</h5>
                    <h2 class="text-danger">@unpaidCount</h2>
                    <p class="text-muted">Total: @unpaidTotal.ToString("C")</p>
                    <a href="billing" class="btn btn-sm btn-outline-danger mt-2">View Billing</a>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool loading = true;
    private List<Appointment> todaysAppointments = new();
    private List<Patient> recentPatients = new();
    private int unpaidCount;
    private decimal unpaidTotal;

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        todaysAppointments = await DbContext.Appointments
            .Include(a => a.Patient)
            .Where(a => a.DateTime.Date == today && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.DateTime)
            .ToListAsync();

        recentPatients = await DbContext.Patients
            .Include(p => p.Owner)
            .OrderByDescending(p => p.Id)
            .Take(5)
            .ToListAsync();

        var unpaidInvoices = await DbContext.Invoices
            .Where(i => !i.IsPaid)
            .ToListAsync();
        unpaidCount = unpaidInvoices.Count;
        unpaidTotal = unpaidInvoices.Sum(i => i.TotalAmount);

        loading = false;
    }
}

