@page "/patients"
@attribute [Authorize]
@inject ApplicationDbContext DbContext
@inject NavigationManager Navigation

<PageTitle>Patients - VetClinic</PageTitle>

<h1 class="mb-4">Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search patients..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="speciesFilter">
            <option value="">All Species</option>
            <option value="Dog">Dog</option>
            <option value="Cat">Cat</option>
            <option value="Bird">Bird</option>
            <option value="Rabbit">Rabbit</option>
            <option value="Other">Other</option>
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary w-100" @onclick="() => showAddForm = true">Add New Patient</button>
    </div>
</div>

@if (showAddForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Add New Patient</h5>
            <EditForm Model="newPatient" OnValidSubmit="AddPatient" FormName="addPatient">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="newPatient.Name" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="newPatient.Species" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="newPatient.Breed" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="newPatient.DateOfBirth" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="newPatient.OwnerId">
                            <option value="0">Select Owner...</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <button type="submit" class="btn btn-success me-2">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showAddForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (loading)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Date of Birth</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var patient in FilteredPatients)
            {
                <tr style="cursor:pointer" @onclick="() => Navigation.NavigateTo($&quot;patients/{patient.Id}&quot;)">
                    <td>@patient.Name</td>
                    <td>@patient.Species</td>
                    <td>@patient.Breed</td>
                    <td>@patient.Owner.FirstName @patient.Owner.LastName</td>
                    <td>@patient.DateOfBirth?.ToString("yyyy-MM-dd")</td>
                </tr>
            }
        </tbody>
    </table>

    @if (!FilteredPatients.Any())
    {
        <p class="text-muted">No patients found.</p>
    }
}

@code {
    private bool loading = true;
    private bool showAddForm;
    private string searchTerm = string.Empty;
    private string speciesFilter = string.Empty;
    private List<Patient> patients = new();
    private List<Owner> owners = new();
    private Patient newPatient = new();

    private IEnumerable<Patient> FilteredPatients => patients.Where(p =>
        (string.IsNullOrEmpty(searchTerm) || p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) || p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)) &&
        (string.IsNullOrEmpty(speciesFilter) || p.Species.Equals(speciesFilter, StringComparison.OrdinalIgnoreCase)));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
        loading = false;
    }

    private async Task LoadData()
    {
        patients = await DbContext.Patients.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await DbContext.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private async Task AddPatient()
    {
        if (newPatient.OwnerId == 0) return;
        DbContext.Patients.Add(newPatient);
        await DbContext.SaveChangesAsync();
        newPatient = new Patient();
        showAddForm = false;
        await LoadData();
    }
}

