@code {
    [Parameter] public int Id { get; set; }

    private bool loading = true;
    private bool showAddRecord;
    private bool saveSuccess;
    private Patient? patient;
    private List<Owner> owners = new();
    private List<MedicalRecord> medicalRecords = new();
    private MedicalRecord newRecord = new();

    protected override async Task OnInitializedAsync()
    {
        patient = await DbContext.Patients.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == Id);
        owners = await DbContext.Owners.OrderBy(o => o.LastName).ToListAsync();
        if (patient != null)
        {
            medicalRecords = await DbContext.MedicalRecords
                .Where(m => m.PatientId == Id)
                .OrderByDescending(m => m.Date)
                .ToListAsync();
        }
        loading = false;
    }

    private async Task SavePatient()
    {
        await DbContext.SaveChangesAsync();
        saveSuccess = true;
        await Task.Delay(2000);
        saveSuccess = false;
    }

    private async Task AddRecord()
    {
        newRecord.PatientId = Id;
        newRecord.Date = DateTime.Now;
        DbContext.MedicalRecords.Add(newRecord);
        await DbContext.SaveChangesAsync();
        medicalRecords.Insert(0, newRecord);
        newRecord = new MedicalRecord();
        showAddRecord = false;
    }
}

