@page "/appointments"
@attribute [Authorize]
@inject ApplicationDbContext DbContext

<PageTitle>Appointments - VetClinic</PageTitle>

<h1 class="mb-4">Appointments</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <button class="btn btn-outline-secondary btn-sm" @onclick="PreviousWeek">← Previous</button>
        <span class="mx-2 fw-bold">@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</span>
        <button class="btn btn-outline-secondary btn-sm" @onclick="NextWeek">Next →</button>
    </div>
    <button class="btn btn-primary" @onclick="() => showAddForm = true">New Appointment</button>
</div>

@if (showAddForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Appointment</h5>
            <EditForm Model="newAppointment" OnValidSubmit="AddAppointment" FormName="addAppointment">
                <DataAnnotationsValidator />
                <div class="row">
