                                        AppointmentStatus.Cancelled => "bg-danger",
                                        _ => "bg-primary"
                                    };
                                    <div class="mb-1">
                                        <span class="badge @badgeClass">@apt.Patient.Name</span>
                                        <br/><small>@apt.Reason</small>
                                        @if (apt.Status == AppointmentStatus.Scheduled)
                                        {
                                            <div>
                                                <button class="btn btn-outline-warning btn-sm py-0 px-1 mt-1" @onclick="() => StartReschedule(apt)">Reschedule</button>
                                                <button class="btn btn-outline-danger btn-sm py-0 px-1 mt-1" @onclick="() => CancelAppointment(apt)">Cancel</button>
                                                <button class="btn btn-outline-success btn-sm py-0 px-1 mt-1" @onclick="() => CompleteAppointment(apt)">Complete</button>
                                            </div>
                                        }
                                    </div>
                                }
