+                    <select class="form-select" @bind="invoiceAppointmentId">
+                        <option value="">None</option>
+                        @foreach (var a in patientAppointments)
+                        {
+                            <option value="@a.Id">@a.DateTime.ToString("MM/dd HH:mm") - @a.Reason</option>
+                        }
+                    </select>
+                </div>
+            </div>
+            <h6>Line Items</h6>
+            @for (int i = 0; i < lineItems.Count; i++)
+            {
+                var idx = i;
+                <div class="row mb-1">
+                    <div class="col-md-5">
+                        <input class="form-control form-control-sm" placeholder="Description" @bind="lineItems[idx].Description" />
+                    </div>
+                    <div class="col-md-2">
+                        <input type="number" class="form-control form-control-sm" placeholder="Qty" @bind="lineItems[idx].Quantity" />
+                    </div>
+                    <div class="col-md-3">
+                        <input type="number" step="0.01" class="form-control form-control-sm" placeholder="Unit Price" @bind="lineItems[idx].UnitPrice" />
+                    </div>
+                    <div class="col-md-2">
+                        <button class="btn btn-outline-danger btn-sm" @onclick="() => lineItems.RemoveAt(idx)">Remove</button>
+                    </div>
+                </div>
+            }
+            <button class="btn btn-outline-secondary btn-sm mb-2" @onclick="() => lineItems.Add(new InvoiceLineItem())">+ Add Line</button>
+            <div class="fw-bold mb-2">Total: @lineItems.Sum(li => li.Quantity * li.UnitPrice).ToString("C")</div>
+            <button class="btn btn-success me-2" @onclick="CreateInvoice">Create Invoice</button>
+            <button class="btn btn-secondary" @onclick="() => showNewInvoice = false">Cancel</button>
+        </div>
+    </div>
+}
+
+@if (showPaymentHistory)
+{
+    <div class="card mb-3">
+        <div class="card-body">
+            <h5>Payment History</h5>
+            <table class="table table-sm">
+                <thead>
+                    <tr><th>Date</th><th>Invoice #</th><th>Patient</th><th>Amount</th><th>Method</th></tr>
+                </thead>
+                <tbody>
+                    @foreach (var payment in allPayments)
+                    {
+                        <tr>
+                            <td>@payment.Date.ToString("yyyy-MM-dd")</td>
+                            <td>#@payment.InvoiceId</td>
+                            <td>@payment.Invoice.Patient.Name</td>
+                            <td>@payment.Amount.ToString("C")</td>
+                            <td>@payment.Method</td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+    </div>
+}
+
+@if (loading)
+{
+    <p><em>Loading...</em></p>
+}
+else
+{
+    <table class="table table-striped">
+        <thead>
+            <tr><th>#</th><th>Date</th><th>Patient</th><th>Total</th><th>Status</th><th>Actions</th></tr>
+        </thead>
+        <tbody>
+            @foreach (var invoice in FilteredInvoices)
+            {
+                <tr>
+                    <td>@invoice.Id</td>
+                    <td>@invoice.Date.ToString("yyyy-MM-dd")</td>
+                    <td>@invoice.Patient.Name</td>
+                    <td>@invoice.TotalAmount.ToString("C")</td>
+                    <td>
+                        @if (invoice.IsPaid)
+                        {
+                            <span class="badge bg-success">Paid</span>
+                        }
+                        else
+                        {
+                            <span class="badge bg-warning text-dark">Unpaid</span>
+                        }
+                    </td>
+                    <td>
+                        @if (!invoice.IsPaid)
+                        {
+                            <button class="btn btn-sm btn-outline-success" @onclick="() => StartPayment(invoice)">Pay</button>
+                        }
+                    </td>
+                </tr>
+            }
+        </tbody>
+    </table>
+
+    @if (paymentInvoice != null)
+    {
+        <div class="card mb-3">
+            <div class="card-body">
+                <h5>Process Payment for Invoice #@paymentInvoice.Id</h5>
+                <p>Amount Due: @paymentInvoice.TotalAmount.ToString("C")</p>
+                <div class="row">
+                    <div class="col-md-3">
+                        <label class="form-label">Amount</label>
+                        <input type="number" step="0.01" class="form-control" @bind="paymentAmount" />
+                    </div>
+                    <div class="col-md-3">
+                        <label class="form-label">Method</label>
+                        <select class="form-select" @bind="paymentMethod">
+                            <option value="@PaymentMethod.Cash">Cash</option>
+                            <option value="@PaymentMethod.Card">Card</option>
+                            <option value="@PaymentMethod.Check">Check</option>
+                        </select>
+                    </div>
+                    <div class="col-md-3 d-flex align-items-end">
+                        <button class="btn btn-success me-1" @onclick="ProcessPayment">Confirm</button>
+                        <button class="btn btn-secondary" @onclick="() => paymentInvoice = null">Cancel</button>
+                    </div>
+                </div>
+            </div>
+        </div>
+    }
+}
+
+@code {
+    private bool loading = true;
+    private bool showNewInvoice;
+    private bool showPaymentHistory;
+    private string filter = "all";
+    private List<Invoice> invoices = new();
+    private List<Patient> patients = new();
+    private List<Appointment> patientAppointments = new();
+    private List<Payment> allPayments = new();
+    private List<InvoiceLineItem> lineItems = new() { new InvoiceLineItem() };
+    private int invoicePatientId;
+    private string invoiceAppointmentId = "";
+
+    private Invoice? paymentInvoice;
+    private decimal paymentAmount;
+    private PaymentMethod paymentMethod = PaymentMethod.Cash;
+
+    private IEnumerable<Invoice> FilteredInvoices => filter switch
+    {
+        "unpaid" => invoices.Where(i => !i.IsPaid),
+        "paid" => invoices.Where(i => i.IsPaid),
+        _ => invoices
+    };
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadData();
+        loading = false;
+    }
+
+    private async Task LoadData()
+    {
+        invoices = await DbContext.Invoices.Include(i => i.Patient).OrderByDescending(i => i.Date).ToListAsync();
+        patients = await DbContext.Patients.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
+        allPayments = await DbContext.Payments.Include(p => p.Invoice).ThenInclude(i => i.Patient).OrderByDescending(p => p.Date).ToListAsync();
+    }
+
+    private async Task CreateInvoice()
+    {
+        if (invoicePatientId == 0 || !lineItems.Any(li => !string.IsNullOrEmpty(li.Description))) return;
+
+        var invoice = new Invoice
+        {
+            PatientId = invoicePatientId,
+            AppointmentId = int.TryParse(invoiceAppointmentId, out var aid) ? aid : null,
+            Date = DateTime.Now,
+            TotalAmount = lineItems.Sum(li => li.Quantity * li.UnitPrice)
+        };
+
+        DbContext.Invoices.Add(invoice);
+        await DbContext.SaveChangesAsync();
+
+        foreach (var item in lineItems.Where(li => !string.IsNullOrEmpty(li.Description)))
+        {
+            item.InvoiceId = invoice.Id;
+            DbContext.InvoiceLineItems.Add(item);
+        }
+        await DbContext.SaveChangesAsync();
+
+        lineItems = new List<InvoiceLineItem> { new InvoiceLineItem() };
+        invoicePatientId = 0;
+        invoiceAppointmentId = "";
+        showNewInvoice = false;
+        await LoadData();
+    }
+
+    private void StartPayment(Invoice invoice)
+    {
+        paymentInvoice = invoice;
+        paymentAmount = invoice.TotalAmount;
+    }
+
+    private async Task ProcessPayment()
+    {
+        if (paymentInvoice == null) return;
+
+        var payment = new Payment
+        {
+            InvoiceId = paymentInvoice.Id,
+            Date = DateTime.Now,
+            Amount = paymentAmount,
+            Method = paymentMethod
+        };
+        DbContext.Payments.Add(payment);
+        paymentInvoice.IsPaid = true;
+        await DbContext.SaveChangesAsync();
+        paymentInvoice = null;
+        await LoadData();
+    }
+}
+

