@page "/appointments"
@attribute [Authorize]
@inject ApplicationDbContext DbContext

<PageTitle>Appointments - VetClinic</PageTitle>

<h1 class="mb-4">Appointments</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <button class="btn btn-outline-secondary btn-sm" @onclick="PreviousWeek">&#8592; Previous</button>
        <span class="mx-2 fw-bold">@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</span>
        <button class="btn btn-outline-secondary btn-sm" @onclick="NextWeek">Next &#8594;</button>
    </div>
    <button class="btn btn-primary" @onclick="() => showAddForm = true">New Appointment</button>
</div>

@if (showAddForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Appointment</h5>
            <EditForm Model="newAppointment" OnValidSubmit="AddAppointment" FormName="addAppointment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="newAppointment.PatientId">
                            <option value="0">Select Patient...</option>
                            @foreach (var p in patients)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date and Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newAppointment.DateTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Duration (min)</label>
                        <input type="number" class="form-control" @bind="durationMinutes" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success me-2">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showAddForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (loading)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-bordered">
            <thead>
                <tr>
                    <th style="width:80px">Time</th>
                    @foreach (var header in GetWeekHeaders())
                    {
                        <th class="text-center @header.CssClass">@header.Label</th>
                    }
                </tr>
            </thead>
            <tbody>
                @foreach (var row in GetScheduleRows())
                {
                    <tr>
                        <td class="text-muted small">@row.TimeLabel</td>
                        @foreach (var cell in row.Cells)
                        {
                            <td class="@cell.CssClass" style="font-size:0.8rem; vertical-align:top;">
                                @foreach (var apt in cell.Appointments)
                                {
                                    <div class="mb-1">
                                        <span class="badge @GetBadgeClass(apt.Status)">@apt.Patient.Name</span>
                                        <br><small>@apt.Reason</small>
                                        @if (apt.Status == AppointmentStatus.Scheduled)
                                        {
                                            <div>
                                                <button class="btn btn-outline-warning btn-sm py-0 px-1 mt-1" @onclick="() => StartReschedule(apt)">Reschedule</button>
                                                <button class="btn btn-outline-danger btn-sm py-0 px-1 mt-1" @onclick="() => CancelAppointment(apt)">Cancel</button>
                                                <button class="btn btn-outline-success btn-sm py-0 px-1 mt-1" @onclick="() => CompleteAppointment(apt)">Complete</button>
                                            </div>
                                        }
                                    </div>
                                }
                            </td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>

    @if (rescheduleAppointment != null)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5>Reschedule: @rescheduleAppointment.Patient.Name - @rescheduleAppointment.Reason</h5>
                <div class="row">
                    <div class="col-md-4">
                        <label class="form-label">New Date and Time</label>
                        <input type="datetime-local" class="form-control" @bind="rescheduleDateTime" />
                    </div>
                    <div class="col-md-2 d-flex align-items-end">
                        <button class="btn btn-warning me-1" @onclick="ConfirmReschedule">Confirm</button>
                        <button class="btn btn-secondary" @onclick="() => rescheduleAppointment = null">Cancel</button>
                    </div>
                </div>
            </div>
        </div>
    }

    <div class="mt-3">
        <span class="badge bg-success me-2">Scheduled</span>
        <span class="badge bg-secondary me-2">Completed</span>
        <span class="badge bg-danger me-2">Cancelled</span>
    </div>
}

@code {
    private bool loading = true;
    private bool showAddForm;
    private DateTime weekStart;
    private List<Appointment> weekAppointments = new();
    private List<Patient> patients = new();
    private Appointment newAppointment = new() { DateTime = DateTime.Today.AddHours(9) };
    private int durationMinutes = 30;
    private Appointment? rescheduleAppointment;
    private DateTime rescheduleDateTime;

    private record DayHeader(string Label, string CssClass);
    private record ScheduleCell(string CssClass, List<Appointment> Appointments);
    private record ScheduleRow(string TimeLabel, List<ScheduleCell> Cells);

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-success",
        AppointmentStatus.Completed => "bg-secondary",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };

    private List<DayHeader> GetWeekHeaders()
    {
        var headers = new List<DayHeader>();
        for (int d = 0; d < 7; d++)
        {
            var day = weekStart.AddDays(d);
            var css = day.Date == DateTime.Today ? "table-info" : "";
            headers.Add(new DayHeader(day.ToString("ddd MM\\/dd"), css));
        }
        return headers;
    }

    private List<ScheduleRow> GetScheduleRows()
    {
        var rows = new List<ScheduleRow>();
        for (int hour = 8; hour <= 17; hour++)
        {
            var cells = new List<ScheduleCell>();
            for (int d = 0; d < 7; d++)
            {
                var slotDate = weekStart.AddDays(d).Date;
                var slotAppts = weekAppointments
                    .Where(a => a.DateTime.Date == slotDate && a.DateTime.Hour == hour)
                    .ToList();
                var css = slotAppts.Any() ? "table-warning" : "";
                cells.Add(new ScheduleCell(css, slotAppts));
            }
            rows.Add(new ScheduleRow($"{hour:00}:00", cells));
        }
        return rows;
    }

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday);
        if (DateTime.Today.DayOfWeek == DayOfWeek.Sunday)
            weekStart = weekStart.AddDays(-7);
        await LoadData();
        loading = false;
    }

    private async Task LoadData()
    {
        var weekEnd = weekStart.AddDays(7);
        weekAppointments = await DbContext.Appointments
            .Include(a => a.Patient)
            .Where(a => a.DateTime >= weekStart && a.DateTime < weekEnd)
            .OrderBy(a => a.DateTime)
            .ToListAsync();
        patients = await DbContext.Patients.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task PreviousWeek() { weekStart = weekStart.AddDays(-7); await LoadData(); }
    private async Task NextWeek() { weekStart = weekStart.AddDays(7); await LoadData(); }

    private async Task AddAppointment()
    {
        if (newAppointment.PatientId == 0) return;
        newAppointment.Duration = TimeSpan.FromMinutes(durationMinutes);
        DbContext.Appointments.Add(newAppointment);
        await DbContext.SaveChangesAsync();
        newAppointment = new Appointment { DateTime = DateTime.Today.AddHours(9) };
        durationMinutes = 30;
